import{_ as r,c as i,o as t,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.1.24：桌面端大变身，搜索更统一","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.24.md","filePath":"changelog/v1.1.24.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.24.md"};function n(h,l,s,d,c,p){return t(),i("div",null,[...l[0]||(l[0]=[e('<h1 id="v1-1-24-桌面端大变身-搜索更统一" tabindex="-1">v1.1.24：桌面端大变身，搜索更统一 <a class="header-anchor" href="#v1-1-24-桌面端大变身-搜索更统一" aria-label="Permalink to “v1.1.24：桌面端大变身，搜索更统一”">​</a></h1><p><strong>发布日期</strong>：2026年01月16日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新带来了全新的桌面端布局，支持统一搜索文件和命令，还能自定义项目和会话标题，让管理更顺手。</p><hr><h2 id="新功能-全新桌面端布局与统一搜索" tabindex="-1">新功能：全新桌面端布局与统一搜索 <a class="header-anchor" href="#新功能-全新桌面端布局与统一搜索" aria-label="Permalink to “新功能：全新桌面端布局与统一搜索”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面端（Desktop App）迎来了一次视觉大升级！不仅界面更清爽，最重要的是带来了<strong>统一搜索栏</strong>。</p><h3 id="统一搜索是什么" tabindex="-1">统一搜索是什么？ <a class="header-anchor" href="#统一搜索是什么" aria-label="Permalink to “统一搜索是什么？”">​</a></h3><p>以前你需要分别找文件和命令，现在不需要了。顶部的搜索栏（Search Bar）现在是全能的：</p><ul><li>搜<strong>文件</strong>：快速打开项目中的代码文件。</li><li>搜<strong>命令</strong>：直接运行 OpenCode 的斜杠命令（如 <code>/reset</code>, <code>/search</code> 等）。</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开桌面端应用。</li><li>点击顶部的搜索栏（或者留意是否有快捷键提示，通常是 <code>Cmd+K</code> 或 <code>Ctrl+K</code>）。</li><li>输入你想找的文件名或命令，直接跳转。</li></ol><hr><h2 id="新功能-自定义项目和会话标题" tabindex="-1">新功能：自定义项目和会话标题 <a class="header-anchor" href="#新功能-自定义项目和会话标题" aria-label="Permalink to “新功能：自定义项目和会话标题”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>OpenCode 会根据对话内容自动生成会话标题，有时候 AI 起的名字不够直观，或者你想给项目起个更好记的名字。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>你终于可以自己改名了！</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li><strong>重命名会话</strong>：在侧边栏找到你想改名的会话，点击标题旁边的编辑图标（通常是铅笔形状），输入新名字回车即可。</li><li><strong>重命名项目</strong>：同样的方式，你可以管理你的项目列表，让它们井井有条。</li></ol><hr><h2 id="新功能-carbonfox-主题" tabindex="-1">新功能：Carbonfox 主题 <a class="header-anchor" href="#新功能-carbonfox-主题" aria-label="Permalink to “新功能：Carbonfox 主题”">​</a></h2><h3 id="这是什么" tabindex="-1">这是什么？ <a class="header-anchor" href="#这是什么" aria-label="Permalink to “这是什么？”">​</a></h3><p>新增了一款名为 <strong>Carbonfox</strong> 的深色主题，专为喜欢极简、高对比度风格的开发者设计。</p><h3 id="如何切换" tabindex="-1">如何切换？ <a class="header-anchor" href="#如何切换" aria-label="Permalink to “如何切换？”">​</a></h3><p>在终端或应用中输入：</p>',28),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"/theme select")])],-1),e('<p>然后选择 <code>Carbonfox</code> 即可体验。</p><hr><h2 id="改进-mcp-oauth-配置" tabindex="-1">改进：MCP OAuth 配置 <a class="header-anchor" href="#改进-mcp-oauth-配置" aria-label="Permalink to “改进：MCP OAuth 配置”">​</a></h2><h3 id="这是什么-1" tabindex="-1">这是什么？ <a class="header-anchor" href="#这是什么-1" aria-label="Permalink to “这是什么？”">​</a></h3><p>对于使用 Model Context Protocol (MCP) 的高级用户，现在支持配置 OAuth 重定向 URI 了。这意味着你可以更方便地连接需要复杂认证的 MCP 服务器。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用桌面端 App</td><td>✅ <strong>强烈建议升级</strong>，新布局和搜索太好用了</td></tr><tr><td>经常需要管理多会话</td><td>✅ 升级，改名功能很实用</td></tr><tr><td>只用终端 CLI</td><td>可以升级，有一些 TUI 的小优化</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',9),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><p><strong>核心功能 (Core)</strong></p><ul><li>升级 OpenTUI 至 v0.1.74，修复 tmux 下 kitty 键盘的兼容性问题</li><li>确保工具附件不会被当作用户消息发送</li><li>在 config.ts 中使用动态导入处理 session event，避免循环依赖</li><li>修复文档中的失效 URL</li><li>修复 GPT 模型的 itemId 剥离逻辑</li><li>新增 MCP 服务器的 OAuth 重定向 URI 配置</li><li>调整网页搜索工具，强调当前日期并明确说明已不再是 2024 年</li><li>优化文档中关于 question 工具的使用指导</li><li>将 OpenCode 设为大多数推理请求的 User-Agent</li><li>远程会话中无法打开浏览器时，显示认证 URL</li><li>在更多场景下剥离 item IDs</li><li>修复子任务调用时意外更改主模型/Agent 的问题</li><li>修复 ACP 和无头模式下的默认 Agent 选择</li><li>新增 LiteLLM 代理提供商选项，提升兼容性</li></ul><p><strong>终端界面 (TUI)</strong></p><ul><li>在会话头部和 /status 对话框中显示版本号</li><li>修正 TUI 中主题数量的提示信息</li><li>调暗终端 UI 中问题选项的前缀样式</li><li>新增终端界面中问题的 Tab 键导航支持</li><li>新增 Carbonfox 主题</li></ul><p><strong>桌面端 (Desktop)</strong></p><ul><li>新增编辑项目和会话标题的功能</li><li>导航至工作区内的会话时自动打开该工作区</li><li>修复工作区无法展开的问题</li><li>修复展开工作区时页面跳动的问题</li><li>鼠标悬停时截断过长的工作区名称</li><li>修复应用中新建会话的处理逻辑</li><li>将对话框居中到页面而非会话区域</li><li>持久化工作区顺序和折叠状态</li><li>新增统一搜索功能，可同时搜索命令和文件</li><li>为会话列表添加骨架屏加载效果</li><li>修复项目头像的圆角问题</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=r(o,[["render",n]]);export{_ as __pageData,g as default};
